#include <iostream>
#include <vector>

using namespace std;

struct ListNode {
    int val;
    ListNode* next;
    ListNode(int val) : val(val), next(nullptr) {}
};

class Solution {
public:
    // Function to delete a node at a given index
    void deleteAtIndex(ListNode* &head, int index) {
        if (index == 0) {
            head = head->next;
        } else {
            ListNode* cur = head;
            while (index-- > 0 && cur->next != nullptr) {
                cur = cur->next;
            }
            if (cur->next != nullptr) {
                cur->next = cur->next->next;
            }
        }
    }
};

// Function to print the list
void printList(ListNode* head) {
    while (head) {
        cout << head->val << ' ';
        head = head->next;
    }
    cout << '
';
}

int main() {
    int n;
    cin >> n;
    int arr[n];

    for (int i = 0; i < n; i++) {
        cin >> arr[i];
    }

    ListNode* head = new ListNode(arr[0]);
    ListNode* m = head;
    for (int i = 1; i < n; i++) {
        m->next = new ListNode(arr[i]);
        m = m->next;
    }

    // Read from std::cin and remove
    int index;
    cin >> index;
    deleteAtIndex(head, index - 1);

    // Print the final list
    printList(head);
    return 0;
}
